#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define LD long double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define pDD pair<LD,LD>
#define fr first
#define se second
#define pb push_back
#define isr insert
#define _i128 __int128
using namespace std;
const int N = 2e5+5;
int n,m,bcnt,ans[N];
int tr[505][505],pos[N];
struct number{
    int x,y,val;
}b[N];
struct node{
    int id,X1,Y1,X2,Y2,k;
}q[N],q1[N],q2[N];
int read(){
    int su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}
bool cmp(number n1,number n2){
    return n1.val<n2.val;
}
void upd(int x,int y,int k){
    for(int i=x;i<=n;i+=i&-i)
        for(int j=y;j<=n;j+=j&-j)tr[i][j]+=k;
    return;
}
int ask(int x,int y){
    int sum=0;
    for(int i=x;i;i-=i&-i)
        for(int j=y;j;j-=j&-j)sum+=tr[i][j];
    return sum;
}
int query(int X1,int Y1,int X2,int Y2){
    return ask(X2,Y2)-ask(X1-1,Y2)-ask(X2,Y1-1)+ask(X1-1,Y1-1);
}
void solve(int l,int r,int L,int R){
    if(L>R)return;
    if(l==r){
        for(int i=L;i<=R;i++)
            ans[q[i].id]=b[l].val;
        return;
    }
    int mid=(l+r)>>1,p1=0,p2=0;
    for(int i=l;i<=mid;i++)upd(b[i].x,b[i].y,1);
    for(int i=L;i<=R;i++){
        int tmp=query(q[i].X1,q[i].Y1,q[i].X2,q[i].Y2);
        if(tmp>=q[i].k)q1[++p1]=q[i];
        else q[i].k-=tmp,q2[++p2]=q[i];
    }
    for(int i=1;i<=p1;i++)q[L+i-1]=q1[i];
    for(int i=1;i<=p2;i++)q[R-p2+i]=q2[i];
    for(int i=l;i<=mid;i++)upd(b[i].x,b[i].y,-1);
    solve(l,mid,L,L+p1-1);
    solve(mid+1,r,R-p2+1,R);return;
}
int main(){
    n=read(),m=read();bcnt=0;
    for(int i=1;i<=n;i++)
        for(int j=1;j<=n;j++){
            int x=read();
            b[++bcnt]={i,j,x};
        }
    sort(b+1,b+bcnt+1,cmp);
    for(int i=1;i<=m;i++){
        int X1=read(),Y1=read();
        int X2=read(),Y2=read(),k=read();
        q[i]={i,X1,Y1,X2,Y2,k};
    }
    solve(1,bcnt,1,m);
    for(int i=1;i<=m;i++)cout<<ans[i]<<"\n";
    return 0;
}
